const maskPhone = (phone = '') => phone.replace(/^(\+?\d{3})\d+(\d{4})$/, '$1****$2');
const displayTime = (v?: string) => v ? dayjs(v).format('YYYY-MM-DD HH:mm:ss') : '-';
const toIso = (v: any) => v ? v.toISOString() : undefined;
const stringify = (v: unknown) => v === undefined || v === null ? '' : (typeof v === 'string' ? v : JSON.stringify(v, null, 2));
const compact = (v: unknown, len = 80) => { const t = stringify(v).replace(/\s+/g, ' ').trim(); return t ? (t.length > len ? `${t.slice(0, len)}...` : t) : '-'; };
const normalizeUrlText = (v: unknown) => { const text = String(v ?? ''); return text.startsWith('//') ? `https:${text}` : text; };
const isHttpUrlText = (v: unknown) => /^https?:\/\//i.test(normalizeUrlText(v).trim());
const renderTableText = (value: unknown, limit = 80, className = 'table-cell-text') => {
  const full = stringify(value ?? '-');
  const normalized = normalizeUrlText(full).trim();
  const text = compact(normalized || value || '-', limit);
  const node = isHttpUrlText(normalized)
    ? <a className={`${className} table-cell-link`} href={normalized} target="_blank" rel="noreferrer" onClick={e=>e.stopPropagation()}>{text}</a>
    : <span className={className}>{text}</span>;
  return <Tooltip overlayClassName="table-cell-tooltip" placement="topLeft" mouseEnterDelay={0.45} title={normalized || full}>{node}</Tooltip>;
};
const isUrlLikeField = (key = '', value?: unknown) => {
  const k = String(key).toLowerCase(); const text = String(value ?? '');
  return text.startsWith('http://') || text.startsWith('https://') || text.startsWith('//') || ['url','link','链接','图片','pic','image'].some(x => k.includes(x));
};
const labelColumnWidth = (key: string) => isUrlLikeField(key) ? 220 : key.length > 8 ? 180 : 150;

const safeDecodeText = (v?: unknown) => { const raw = String(v ?? '').trim(); if (!raw) return ''; try { return decodeURIComponent(raw.replace(/\+/g, ' ')); } catch { try { return decodeURIComponent(raw); } catch { return raw; } } };
const methodColor = (m?: string) => ({GET:'blue',POST:'green',PUT:'orange',PATCH:'purple',DELETE:'red'}[String(m||'').toUpperCase()] || 'default');
const statusColor = (s?: number) => !s ? 'default' : s >= 500 ? 'red' : s >= 400 ? 'orange' : s >= 300 ? 'cyan' : 'green';
const errMsg = (e:any) => Array.isArray(e?.response?.data?.detail) ? e.response.data.detail.map((x:any)=>x.msg || JSON.stringify(x)).join('；') : e?.response?.data?.detail || e?.response?.data?.message || e?.message || '请求失败';
function escapeHtml(value: unknown) { return String(value ?? '').replace(/[&<>'"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[ch] || ch)); }
function downloadExcel(rows: Record<string, unknown>[], filename: string, headers: string[]) {
  const table = `<table border="1"><thead><tr>${headers.map(h=>`<th>${escapeHtml(h)}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${headers.map(h=>`<td style="mso-number-format:'\\@';vertical-align:top;white-space:pre-wrap;">${escapeHtml(r[h])}</td>`).join('')}</tr>`).join('')}</tbody></table>`;
  const blob = new Blob([`<!doctype html><html><head><meta charset="UTF-8"></head><body>${table}</body></html>`], { type: 'application/vnd.ms-excel;charset=utf-8' });
  const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = filename; document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url);
}

function Auth({ onAuthed }: { onAuthed: (u: User) => void }) {
  const [tab, setTab] = useState('login'); const [loading, setLoading] = useState(false);
  const submit = async (values: { phone:string; password:string; confirm?:string }) => {
    if (tab === 'register' && values.password !== values.confirm) return message.error('两次密码不一致');
    setLoading(true);
    try { const { data } = await api.post(`/api/user/${tab}`, { phone: values.phone, password: values.password }); if (data.code !== 0) throw new Error(data.message || '请求失败'); if (tab === 'register') { message.success('注册成功，请登录'); setTab('login'); return; } const user = data.user || { id: data.userId, phone: data.phone }; localStorage.setItem('token', data.token); localStorage.setItem('user', JSON.stringify(user)); message.success('登录成功'); onAuthed(user); }
    catch(e:any){ message.error(errMsg(e)); } finally { setLoading(false); }
  };
  return <div className="auth-page"><div className="auth-bg auth-bg-a"/><div className="auth-bg auth-bg-b"/><Card className="auth-card" bordered={false}>
    <div className="auth-logo"><div className="logo-mark">A</div><h1>API Capture</h1><p>接口数据解析与管理平台</p></div>
    <Tabs centered activeKey={tab} onChange={setTab} items={[{key:'login',label:'登录'},{key:'register',label:'注册'}]}/>
    <Form layout="vertical" onFinish={submit} size="large" autoComplete="off"><Form.Item name="phone" label="手机号" rules={[{required:true,message:'请输入手机号'},{pattern:/^\+?\d{5,20}$/,message:'手机号格式不正确'}]}><Input prefix="📱" placeholder="13800138000"/></Form.Item><Form.Item name="password" label="密码" rules={[{required:true,message:'请输入密码'},{min:6,message:'密码至少6位'}]}><Input.Password prefix="🔒" placeholder="至少6位"/></Form.Item>{tab==='register'&&<Form.Item name="confirm" label="确认密码" rules={[{required:true,message:'请确认密码'}]}><Input.Password prefix="✅"/></Form.Item>}<Button type="primary" htmlType="submit" loading={loading} block className="gradient-btn">{tab==='login'?'登录':'注册'}</Button></Form>
  </Card></div>;
}

