  const setLabelFieldFilter=(key:string,value:string)=>setLabelDataFieldFilters(prev=>({...prev,[key]:value}));
  const toggleFilterField=(key:string,checked:boolean)=>{setSelectedFilterFields(prev=>checked?[...new Set([...prev,key])]:prev.filter(x=>x!==key));if(!checked)setLabelDataFieldFilters(prev=>{const next={...prev};delete next[key];return next;});};
  const exportLabelData=async()=>{if(!selectedLabelId)return message.warning('请先选择标签');const effectiveFilters=Object.fromEntries(Object.entries(labelDataFieldFilters).filter(([k,v])=>selectedFilterFields.includes(k)&&String(v||'').trim()));setLabelDataExporting(true);try{const {data}=await api.get('/api/label-data/export',{params:{labelId:selectedLabelId,keyword:labelDataKeyword.trim()||undefined,fieldFilters:JSON.stringify(effectiveFilters),startTime:toIso(labelDataRange?.[0]),endTime:toIso(labelDataRange?.[1])}});const cols:string[]=data.data.columns||[];const headers=['入库时间','标签','规则',...cols,'原始数据'];const out=(data.data.list||[]).map((r:LabelDataRecord)=>Object.fromEntries(headers.map(h=>[h,h==='入库时间'?displayTime(r.created_at):h==='标签'?r.label_name:h==='规则'?(r.rule_name||''):h==='原始数据'?stringify(r.raw_item):(r.row_data||{})[h]])));downloadExcel(out,`标签数据_${dayjs().format('YYYYMMDD_HHmmss')}.xls`,headers);message.success('标签数据导出成功');}catch(e:any){message.error(errMsg(e));}finally{setLabelDataExporting(false);}};
