  const openSample=async()=>{setSampleMode('history');setSampleListCandidates([]);if(!ruleForm.url_pattern.trim())return message.warning('请先填写 URL 匹配');setSampleOpen(true);setSampleLoading(true);try{const {data}=await api.get('/api/rules/sample-fields',{params:{urlPattern:ruleForm.url_pattern.trim(),responseListPath:ruleForm.response_list_path||undefined,method:ruleForm.method||undefined}});const fields=data.data?.fields||[];setSampleFields(fields);setSampleInfo(data.data||{});const preferred=new Set(['nick','shopInfo.title','item_id','realSales','price','priceShow.price','title','auctionURL','pic_path']);setSampleSelectedKeys(fields.filter((f:SampleField)=>preferred.has(f.path)).map((f:SampleField)=>f.path));if(!fields.length)message.warning('没有找到样本字段，请先捕获并上报该接口');}catch(e:any){message.error(errMsg(e));}finally{setSampleLoading(false);}};
  const parsePastedResponse=async(path?:string)=>{if(!sampleResponseText.trim())return message.warning('请先粘贴 Response JSON/JSONP');setSampleMode('paste');setSampleOpen(true);setSampleLoading(true);try{const {data}=await api.post('/api/rules/sample-fields-from-response',{response:sampleResponseText,response_list_path:(path ?? ruleForm.response_list_path) || undefined});const fields=data.data?.fields||[];setSampleFields(fields);setSampleInfo(data.data||{});setSampleListCandidates(data.data?.listCandidates||[]);if(data.data?.responseListPath!==undefined)setRuleForm(prev=>({...prev,response_list_path:data.data.responseListPath||prev.response_list_path}));const preferred=new Set(['nick','shopInfo.title','item_id','SkuId','wareId','realSales','price','priceShow.price','title','wareName','auctionURL','pic_path']);setSampleSelectedKeys(fields.filter((f:SampleField)=>preferred.has(f.path)).map((f:SampleField)=>f.path));if(!fields.length)message.warning('没有从粘贴内容里识别到字段，请检查列表路径');else message.success(`已识别 ${fields.length} 个字段`);}catch(e:any){message.error(errMsg(e));}finally{setSampleLoading(false);}};
  const applySample=()=>{const selected=sampleFields.filter(f=>sampleSelectedKeys.includes(f.path));if(!selected.length)return message.warning('请至少选择一个字段');const mapping:Record<string,unknown>={};selected.forEach(f=>mapping[f.path]=f.label||f.path);setRuleForm({...ruleForm,field_mapping:JSON.stringify(mapping,null,2)});setSampleOpen(false);};
