  const applyCurl=()=>{if(!curlResult)return message.warning('请先解析 cURL');setRuleForm({...ruleForm,name:ruleForm.name||curlResult.suggested_name||'',method:curlResult.method||'',url_pattern:curlResult.url_pattern||'',url_match_type:curlResult.url_match_type||'contains',params_filter:JSON.stringify(curlResult.params_filter||{},null,2),remark:ruleForm.remark||`由 cURL 导入：${curlResult.url||''}`});setCurlOpen(false);message.success('已填充 URL、方法和 Params 过滤，可继续选择标签/字段映射');scrollToRuleEditor();};
  const openRuleTest=async(r:RuleRow)=>{setRuleTestOpen(true);setRuleTestRule(r);setRuleTestResult(null);setRuleTestLoading(true);try{const {data}=await api.get(`/api/rules/${r.id}/test`);setRuleTestResult(data.data);if(data.data?.matched)message.success(`规则测试通过，解析 ${data.data.parsedCount||0} 行`);else message.warning(data.data?.message||'未找到命中样本');}catch(e:any){message.error(errMsg(e));}finally{setRuleTestLoading(false);}};

  const openLabelDetail=async(id:number)=>{setLabelDataDetailLoading(true);try{const {data}=await api.get(`/api/label-data/${id}`);setLabelDataDetail(data.data);}catch(e:any){message.error(errMsg(e));}finally{setLabelDataDetailLoading(false);}};
  const pageMeta:Record<string,{title:string;desc:string;eyebrow:string}>={dashboard:{title:'接口数据看板',desc:'实时观察捕获规模、失败接口、慢接口与高频域名',eyebrow:'Overview'},data:{title:'我的捕获接口数据',desc:'按时间、URL、方法和状态快速定位每一次接口请求',eyebrow:'API Records'},rules:{title:'过滤解析规则',desc:'维护公共规则池，选择要启用到插件的解析策略',eyebrow:'Rule Center'},labelData:{title:'标签数据表',desc:'按标签查看规则拆出来的结构化字段数据',eyebrow:'Parsed Tables'},profile:{title:'个人中心',desc:'查看账号、当前 API 地址和本地部署状态',eyebrow:'Account'}};
